// GOOD: Only the unsafe part is in an unsafe block
/// Process a raw buffer.
///
/// # Safety
/// - `data` must be non-null and point to `len` valid bytes
/// - The memory must not be modified during this call
pub unsafe fn process_buffer(data: *const u8, len: usize) -> Vec<u8> {
    // SAFETY: Caller guarantees data is valid for len bytes
    let slice = unsafe { std::slice::from_raw_parts(data, len) };

    // Everything below is safe Rust
    slice.iter().map(|&b| b.wrapping_add(1)).collect()
}

pub struct FixedBuffer {
    data: Vec<u8>,
    len: usize,
}

impl FixedBuffer {
    pub fn new(capacity: usize) -> Self {
        FixedBuffer {
            data: vec![0u8; capacity],
            len: 0,
        }
    }

    pub fn push(&mut self, byte: u8) -> bool {
        if self.len >= self.data.len() {
            return false;
        }
        // SAFETY: We just checked that len < data.len(),
        // so this index is within bounds.
        unsafe {
            *self.data.get_unchecked_mut(self.len) = byte;
        }
        self.len += 1;
        true
    }

    pub fn as_slice(&self) -> &[u8] {
        // SAFETY: self.len is always <= self.data.len()
        // because push() checks before incrementing,
        // and no other method increases len.
        unsafe {
            self.data.get_unchecked(..self.len)
        }
    }
}

// When reviewing unsafe code, check:
//
// 1. SCOPE: Is the unsafe block as small as possible?
//    - Only the operations requiring unsafe should be inside the block
//
// 2. DOCUMENTATION: Is there a # Safety section in the doc comment?
//    - What are the preconditions?
//    - What invariants must hold?
//
// 3. SAFETY COMMENT: Is there a // SAFETY: comment on each unsafe block?
//    - Explains WHY the invariants hold at this point
//
// 4. POINTERS: For each pointer dereference:
//    - Is it guaranteed non-null?
//    - Is it guaranteed to point to valid memory?
//    - Is the memory initialized?
//    - Is it properly aligned?
//    - Are there no aliasing violations?
//
// 5. LIFETIMES: Does the unsafe code respect lifetime guarantees?
//    - No returning references to local variables
//    - No use-after-free
//
// 6. THREAD SAFETY: If Send/Sync are implemented:
//    - Is concurrent access properly synchronized?
//    - Are there potential data races?
//
// 7. TESTING: Is the code tested with Miri?
//    - cargo +nightly miri test

/// A simple bump allocator.
/// The public API is completely safe.
pub struct BumpAllocator {
    buffer: Vec<u8>,
    offset: usize,
}

impl BumpAllocator {
    pub fn new(capacity: usize) -> Self {
        BumpAllocator {
            buffer: vec![0u8; capacity],
            offset: 0,
        }
    }

    pub fn alloc(&mut self, size: usize) -> Option<&mut [u8]> {
        let align = 8; // Align to 8 bytes
        let aligned_offset = (self.offset + align - 1) & !(align - 1);

        if aligned_offset + size > self.buffer.len() {
            return None; // Out of memory
        }

        let start = aligned_offset;
        self.offset = aligned_offset + size;

        // SAFETY: start..start+size is within buffer bounds
        // (checked above), and we're the only ones who can
        // access this region (offset only increases).
        Some(&mut self.buffer[start..start + size])
    }

    pub fn used(&self) -> usize {
        self.offset
    }

    pub fn remaining(&self) -> usize {
        self.buffer.len() - self.offset
    }

    pub fn reset(&mut self) {
        self.offset = 0;
    }
}

fn main() {
    let mut alloc = BumpAllocator::new(1024);

    if let Some(buf) = alloc.alloc(64) {
        buf[0] = 42;
        println!("Allocated 64 bytes, used: {}", alloc.used());
    }

    if let Some(buf) = alloc.alloc(128) {
        buf.fill(0xFF);
        println!("Allocated 128 more bytes, used: {}", alloc.used());
    }
}
